esqlQuery.esql:
// Alert when replication agreement errors are detected.
// Replication failures can cause split-brain and data inconsistency.
// Groups by agreement name and remote host.
FROM logs-freeipa.directory_errors-*
| WHERE freeipa.directory_error.agreement IS NOT NULL
| STATS error_count = COUNT(*) BY freeipa.directory_error.agreement, freeipa.directory_error.remote_host
| WHERE error_count >= 1
